import numpy as np

def predict(frame, action):  # frame: (64,64) int; action: 1-indexed
    out = frame.copy()
    H, W = out.shape
    CURSOR, TRAIL, COUNTER, BG = 14, 2, 3, 4

    # locate the 2x2 cursor block (all four cells == 14)
    is14 = (out == CURSOR)
    cur = None
    for r in range(H - 1):
        for c in range(W - 1):
            if is14[r, c] and is14[r, c+1] and is14[r+1, c] and is14[r+1, c+1]:
                cur = (r, c); break
        if cur is not None:
            break

    deltas = {1: (-2, 0), 2: (2, 0), 3: (0, -2), 4: (0, 2)}  # up,down,left,right
    moved = False
    if cur is not None and action in deltas:
        r, c = cur
        dr, dc = deltas[action]
        nr, nc = r + dr, c + dc
        if 0 <= nr <= H - 2 and 0 <= nc <= W - 2:
            dest = out[nr:nr+2, nc:nc+2]
            # only move onto background/trail/itself (blocked by obstacles)
            if np.all((dest == BG) | (dest == TRAIL) | (dest == CURSOR)):
                out[r:r+2, c:c+2] = TRAIL      # vacated -> trail
                out[nr:nr+2, nc:nc+2] = CURSOR  # new pos -> cursor
                moved = True

    # bottom-row step counter (color 3), advances for actions {1,4,6}
    if action == 6 or (moved and action in (1, 4)):
        col = int(np.count_nonzero(out[H - 1] == COUNTER))
        if col < W:
            out[H - 1, col] = COUNTER

    return out
